/* 基础重置 */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Poppins', sans-serif;
    background: linear-gradient(135deg, #6a11cb 0%, #2575fc 100%);
    color: #333;
    min-height: 100vh;
    padding: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 900px;
    background-color: rgba(255, 255, 255, 0.95);
    border-radius: 24px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    overflow: hidden;
    padding: 30px;
    margin: 20px;
}

/* 头部样式 */
header {
    text-align: center;
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 2px solid #f0f0f0;
}

header h1 {
    font-size: 2.8rem;
    color: #2d3436;
    margin-bottom: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 15px;
}

header h1 i {
    color: #6a11cb;
}

.subtitle {
    font-size: 1.2rem;
    color: #636e72;
    font-weight: 300;
}

/* 应用包装器 */
.app-wrapper {
    display: flex;
    flex-direction: column;
    gap: 25px;
}

/* 输入区域 */
.input-section {
    background-color: #f8f9fa;
    padding: 25px;
    border-radius: 18px;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);
}

.input-group {
    display: flex;
    gap: 15px;
    margin-bottom: 20px;
}

#taskInput {
    flex: 1;
    padding: 18px 20px;
    border: 2px solid #dfe6e9;
    border-radius: 12px;
    font-size: 1.1rem;
    font-family: 'Poppins', sans-serif;
    transition: all 0.3s ease;
}

#taskInput:focus {
    outline: none;
    border-color: #6a11cb;
    box-shadow: 0 0 0 3px rgba(106, 17, 203, 0.2);
}

#addBtn {
    background: linear-gradient(to right, #6a11cb, #2575fc);
    color: white;
    border: none;
    padding: 18px 30px;
    border-radius: 12px;
    font-size: 1.1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 10px;
}

#addBtn:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 20px rgba(106, 17, 203, 0.3);
}

#addBtn:active {
    transform: translateY(0);
}

.filter-section {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
}

.filter-btn {
    padding: 12px 24px;
    border-radius: 10px;
    border: 2px solid #dfe6e9;
    background-color: white;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.3s ease;
}

.filter-btn.active {
    background-color: #6a11cb;
    color: white;
    border-color: #6a11cb;
}

.filter-btn:hover:not(.active) {
    background-color: #f1f3f4;
}

/* 统计区域 */
.stats-section {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 20px;
}

.stat-card {
    background: linear-gradient(to bottom right, #ffffff, #f8f9fa);
    padding: 25px;
    border-radius: 18px;
    text-align: center;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);
    border: 1px solid #e9ecef;
    transition: transform 0.3s ease;
}

.stat-card:hover {
    transform: translateY(-5px);
}

.stat-card h3 {
    font-size: 1.1rem;
    color: #636e72;
    margin-bottom: 15px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
}

.stat-card p {
    font-size: 3rem;
    font-weight: 700;
    color: #2d3436;
}

/* 任务列表区域 */
.task-list-section {
    background-color: #f8f9fa;
    padding: 25px;
    border-radius: 18px;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);
}

.task-list-section h2 {
    font-size: 1.8rem;
    color: #2d3436;
    margin-bottom: 20px;
    display: flex;
    align-items: center;
    gap: 15px;
}

.task-list {
    min-height: 300px;
    max-height: 400px;
    overflow-y: auto;
    padding-right: 10px;
}

.task-list::-webkit-scrollbar {
    width: 8px;
}

.task-list::-webkit-scrollbar-track {
    background: #f1f1f1;
    border-radius: 10px;
}

.task-list::-webkit-scrollbar-thumb {
    background: #c1c1c1;
    border-radius: 10px;
}

.task-list::-webkit-scrollbar-thumb:hover {
    background: #a1a1a1;
}

.empty-state {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    height: 300px;
    color: #b2bec3;
}

.empty-state i {
    font-size: 5rem;
    margin-bottom: 20px;
}

.empty-state p {
    font-size: 1.3rem;
    text-align: center;
}

.task-item {
    background-color: white;
    padding: 20px;
    border-radius: 14px;
    margin-bottom: 15px;
    display: flex;
    align-items: center;
    gap: 20px;
    transition: all 0.3s ease;
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.03);
    border-left: 5px solid #6a11cb;
}

.task-item:hover {
    transform: translateX(5px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.08);
}

.task-item.completed {
    opacity: 0.8;
    border-left-color: #00b894;
}

.task-checkbox {
    width: 24px;
    height: 24px;
    cursor: pointer;
    accent-color: #00b894;
}

.task-content {
    flex: 1;
    font-size: 1.1rem;
}

.task-item.completed .task-content {
    text-decoration: line-through;
    color: #636e72;
}

.task-actions {
    display: flex;
    gap: 10px;
}

.task-btn {
    width: 40px;
    height: 40px;
    border-radius: 8px;
    border: none;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    font-size: 1rem;
    transition: all 0.2s ease;
}

.edit-btn {
    background-color: #ffeaa7;
    color: #e17055;
}

.edit-btn:hover {
    background-color: #fdcb6e;
}

.delete-btn {
    background-color: #ff7675;
    color: white;
}

.delete-btn:hover {
    background-color: #e84343;
}

/* 操作区域 */
.actions-section {
    display: flex;
    justify-content: center;
    gap: 20px;
    flex-wrap: wrap;
}

.action-btn {
    padding: 16px 30px;
    border-radius: 12px;
    border: none;
    font-size: 1.1rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 12px;
}

.action-btn.primary {
    background: linear-gradient(to right, #00b894, #00cec9);
    color: white;
}

.action-btn.secondary {
    background: linear-gradient(to right, #fd79a8, #e84393);
    color: white;
}

.action-btn:not(.primary):not(.secondary) {
    background: linear-gradient(to right, #636e72, #2d3436);
    color: white;
}

.action-btn:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
}

.action-btn:active {
    transform: translateY(0);
}

/* 页脚 */
footer {
    margin-top: 30px;
    text-align: center;
    padding-top: 20px;
    border-top: 2px solid #f0f0f0;
    color: #636e72;
    font-size: 0.9rem;
}

/* 响应式设计 */
@media (max-width: 768px) {
    .container {
        padding: 20px;
        margin: 10px;
    }

    header h1 {
        font-size: 2.2rem;
        flex-direction: column;
        gap: 10px;
    }

    .input-group {
        flex-direction: column;
    }

    #addBtn {
        justify-content: center;
    }

    .stats-section {
        grid-template-columns: 1fr;
    }

    .actions-section {
        flex-direction: column;
    }

    .action-btn {
        width: 100%;
        justify-content: center;
    }
}

/* 任务时间样式 */
.task-time {
    font-size: 0.9rem;
    color: #636e72;
    margin-top: 5px;
    display: flex;
    align-items: center;
    gap: 5px;
}

/* 编辑模式 */
.task-edit-input {
    flex: 1;
    padding: 12px 15px;
    border: 2px solid #6a11cb;
    border-radius: 8px;
    font-size: 1.1rem;
    font-family: 'Poppins', sans-serif;
}

.save-edit-btn {
    background-color: #00b894;
    color: white;
}

.cancel-edit-btn {
    background-color: #636e72;
    color: white;
}

