// 待办事项应用
class TodoApp {
    constructor() {
        this.tasks = JSON.parse(localStorage.getItem('todoTasks')) || [];
        this.currentFilter = 'all';

        this.initElements();
        this.bindEvents();
        this.renderTasks();
        this.updateStats();
    }

    // 初始化DOM元素
    initElements() {
        this.taskInput = document.getElementById('taskInput');
        this.addBtn = document.getElementById('addBtn');
        this.taskList = document.getElementById('taskList');
        this.filterButtons = document.querySelectorAll('.filter-btn');
        this.clearCompletedBtn = document.getElementById('clearCompleted');
        this.saveTasksBtn = document.getElementById('saveTasks');
        this.loadTasksBtn = document.getElementById('loadTasks');
        this.totalTasksEl = document.getElementById('totalTasks');
        this.pendingTasksEl = document.getElementById('pendingTasks');
        this.completedTasksEl = document.getElementById('completedTasks');
    }

    // 绑定事件
    bindEvents() {
        // 添加任务
        this.addBtn.addEventListener('click', () => this.addTask());
        this.taskInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') this.addTask();
        });

        // 过滤按钮
        this.filterButtons.forEach(btn => {
            btn.addEventListener('click', () => {
                this.filterButtons.forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                this.currentFilter = btn.dataset.filter;
                this.renderTasks();
            });
        });

        // 清除已完成
        this.clearCompletedBtn.addEventListener('click', () => this.clearCompleted());

        // 保存/加载任务
        this.saveTasksBtn.addEventListener('click', () => this.saveTasks());
        this.loadTasksBtn.addEventListener('click', () => this.loadTasks());
    }

    // 添加新任务
    addTask() {
        const text = this.taskInput.value.trim();
        if (!text) {
            this.showNotification('请输入任务内容', 'error');
            return;
        }

        const newTask = {
            id: Date.now(),
            text: text,
            completed: false,
            createdAt: new Date().toISOString(),
            completedAt: null
        };

        this.tasks.unshift(newTask);
        this.saveToLocalStorage();
        this.renderTasks();
        this.updateStats();
        this.taskInput.value = '';

        this.showNotification('任务添加成功', 'success');
    }

    // 切换任务完成状态
    toggleTask(id) {
        const task = this.tasks.find(t => t.id === id);
        if (task) {
            task.completed = !task.completed;
            task.completedAt = task.completed ? new Date().toISOString() : null;
            this.saveToLocalStorage();
            this.renderTasks();
            this.updateStats();

            const status = task.completed ? '已完成' : '待完成';
            this.showNotification(`任务标记为${status}`, 'info');
        }
    }

    // 删除任务
    deleteTask(id) {
        const taskIndex = this.tasks.findIndex(t => t.id === id);
        if (taskIndex > -1) {
            const taskText = this.tasks[taskIndex].text;
            this.tasks.splice(taskIndex, 1);
            this.saveToLocalStorage();
            this.renderTasks();
            this.updateStats();

            this.showNotification(`任务"${taskText}"已删除`, 'warning');
        }
    }

    // 编辑任务
    editTask(id, newText) {
        const task = this.tasks.find(t => t.id === id);
        if (task && newText.trim()) {
            const oldText = task.text;
            task.text = newText.trim();
            this.saveToLocalStorage();
            this.renderTasks();

            this.showNotification(`任务"${oldText}"已更新`, 'info');
        }
    }

    // 清除已完成任务
    clearCompleted() {
        const completedCount = this.tasks.filter(t => t.completed).length;
        if (completedCount === 0) {
            this.showNotification('没有已完成的任务', 'info');
            return;
        }

        if (confirm(`确定要删除 ${completedCount} 个已完成的任务吗？`)) {
            this.tasks = this.tasks.filter(t => !t.completed);
            this.saveToLocalStorage();
            this.renderTasks();
            this.updateStats();

            this.showNotification(`已删除 ${completedCount} 个已完成任务`, 'success');
        }
    }

    // 保存任务到本地存储
    saveToLocalStorage() {
        localStorage.setItem('todoTasks', JSON.stringify(this.tasks));
    }

    // 保存任务到文件
    saveTasks() {
        const dataStr = JSON.stringify(this.tasks, null, 2);
        const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
        const exportFileDefaultName = '待办事项_备份_' + new Date().toISOString().split('T')[0] + '.json';

        const linkElement = document.createElement('a');
        linkElement.setAttribute('href', dataUri);
        linkElement.setAttribute('download', exportFileDefaultName);
        linkElement.click();

        this.showNotification('任务已保存到文件', 'success');
    }

    // 从文件加载任务
    loadTasks() {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json';

        input.onchange = (e) => {
            const file = e.target.files[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = (event) => {
                try {
                    const loadedTasks = JSON.parse(event.target.result);
                    if (Array.isArray(loadedTasks)) {
                        // 合并任务，避免重复ID
                        const existingIds = new Set(this.tasks.map(t => t.id));
                        const newTasks = loadedTasks.filter(t => !existingIds.has(t.id));

                        if (newTasks.length > 0) {
                            this.tasks = [...this.tasks, ...newTasks];
                            this.saveToLocalStorage();
                            this.renderTasks();
                            this.updateStats();
                            this.showNotification(`成功加载 ${newTasks.length} 个任务`, 'success');
                        } else {
                            this.showNotification('没有新的任务可加载', 'info');
                        }
                    } else {
                        throw new Error('文件格式不正确');
                    }
                } catch (error) {
                    this.showNotification('文件读取失败，请检查文件格式', 'error');
                }
            };
            reader.readAsText(file);
        };

        input.click();
    }

    // 渲染任务列表
    renderTasks() {
        // 根据当前过滤器筛选任务
        let filteredTasks;
        switch (this.currentFilter) {
            case 'pending':
                filteredTasks = this.tasks.filter(t => !t.completed);
                break;
            case 'completed':
                filteredTasks = this.tasks.filter(t => t.completed);
                break;
            default:
                filteredTasks = this.tasks;
        }

        // 清空任务列表
        this.taskList.innerHTML = '';

        // 如果没有任务，显示空状态
        if (filteredTasks.length === 0) {
            const emptyState = document.createElement('div');
            emptyState.className = 'empty-state';
            emptyState.innerHTML = `
                <i class="fas fa-clipboard"></i>
                <p>${this.currentFilter === 'all' ? '暂无任务，添加您的第一个待办事项吧！' :
                    this.currentFilter === 'pending' ? '没有待完成的任务' :
                    '没有已完成的任务'}</p>
            `;
            this.taskList.appendChild(emptyState);
            return;
        }

        // 渲染每个任务
        filteredTasks.forEach(task => {
            const taskElement = this.createTaskElement(task);
            this.taskList.appendChild(taskElement);
        });
    }

    // 创建任务元素
    createTaskElement(task) {
        const taskItem = document.createElement('div');
        taskItem.className = `task-item ${task.completed ? 'completed' : ''}`;
        taskItem.dataset.id = task.id;

        // 格式化时间
        const createdTime = new Date(task.createdAt).toLocaleString('zh-CN');
        const completedTime = task.completedAt ?
            new Date(task.completedAt).toLocaleString('zh-CN') : '';

        taskItem.innerHTML = `
            <input type="checkbox" class="task-checkbox" ${task.completed ? 'checked' : ''}>
            <div class="task-content">
                <div>${this.escapeHtml(task.text)}</div>
                <div class="task-time">
                    <i class="far fa-calendar-plus"></i> ${createdTime}
                    ${completedTime ? `<br><i class="far fa-calendar-check"></i> ${completedTime}` : ''}
                </div>
            </div>
            <div class="task-actions">
                <button class="task-btn edit-btn"><i class="fas fa-edit"></i></button>
                <button class="task-btn delete-btn"><i class="fas fa-trash"></i></button>
            </div>
        `;

        // 绑定事件
        const checkbox = taskItem.querySelector('.task-checkbox');
        const editBtn = taskItem.querySelector('.edit-btn');
        const deleteBtn = taskItem.querySelector('.delete-btn');

        checkbox.addEventListener('change', () => this.toggleTask(task.id));
        deleteBtn.addEventListener('click', () => this.deleteTask(task.id));
        editBtn.addEventListener('click', () => this.enterEditMode(taskItem, task));

        return taskItem;
    }

    // 进入编辑模式
    enterEditMode(taskItem, task) {
        const taskContent = taskItem.querySelector('.task-content');
        const taskActions = taskItem.querySelector('.task-actions');

        const originalHTML = taskContent.innerHTML;
        const originalActions = taskActions.innerHTML;

        // 创建编辑输入框
        taskContent.innerHTML = `
            <input type="text" class="task-edit-input" value="${this.escapeHtml(task.text)}">
        `;

        // 创建编辑按钮
        taskActions.innerHTML = `
            <button class="task-btn save-edit-btn"><i class="fas fa-check"></i></button>
            <button class="task-btn cancel-edit-btn"><i class="fas fa-times"></i></button>
        `;

        const editInput = taskContent.querySelector('.task-edit-input');
        const saveBtn = taskActions.querySelector('.save-edit-btn');
        const cancelBtn = taskActions.querySelector('.cancel-edit-btn');

        // 聚焦输入框
        editInput.focus();
        editInput.select();

        // 保存编辑
        saveBtn.addEventListener('click', () => {
            this.editTask(task.id, editInput.value);
        });

        // 取消编辑
        cancelBtn.addEventListener('click', () => {
            taskContent.innerHTML = originalHTML;
            taskActions.innerHTML = originalActions;
            this.bindTaskEvents(taskItem, task.id);
        });

        // 按Enter保存，按Escape取消
        editInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                this.editTask(task.id, editInput.value);
            }
        });

        editInput.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                taskContent.innerHTML = originalHTML;
                taskActions.innerHTML = originalActions;
                this.bindTaskEvents(taskItem, task.id);
            }
        });
    }

    // 绑定任务事件（编辑模式退出后）
    bindTaskEvents(taskItem, taskId) {
        const checkbox = taskItem.querySelector('.task-checkbox');
        const editBtn = taskItem.querySelector('.edit-btn');
        const deleteBtn = taskItem.querySelector('.delete-btn');

        checkbox.addEventListener('change', () => this.toggleTask(taskId));
        deleteBtn.addEventListener('click', () => this.deleteTask(taskId));
        editBtn.addEventListener('click', () => {
            const task = this.tasks.find(t => t.id === taskId);
            if (task) this.enterEditMode(taskItem, task);
        });
    }

    // 更新统计信息
    updateStats() {
        const total = this.tasks.length;
        const completed = this.tasks.filter(t => t.completed).length;
        const pending = total - completed;

        this.totalTasksEl.textContent = total;
        this.pendingTasksEl.textContent = pending;
        this.completedTasksEl.textContent = completed;
    }

    // 显示通知
    showNotification(message, type = 'info') {
        // 移除现有的通知
        const existingNotification = document.querySelector('.notification');
        if (existingNotification) {
            existingNotification.remove();
        }

        // 创建新通知
        const notification = document.createElement('div');
        notification.className = `notification notification-${type}`;
        notification.innerHTML = `
            <i class="fas fa-${type === 'success' ? 'check-circle' : type === 'error' ? 'exclamation-circle' : type === 'warning' ? 'exclamation-triangle' : 'info-circle'}"></i>
            <span>${message}</span>
        `;

        // 添加样式
        const style = document.createElement('style');
        style.textContent = `
            .notification {
                position: fixed;
                top: 20px;
                right: 20px;
                padding: 15px 25px;
                border-radius: 12px;
                color: white;
                font-weight: 500;
                display: flex;
                align-items: center;
                gap: 12px;
                box-shadow: 0 10px 30px rgba(0,0,0,0.2);
                z-index: 1000;
                animation: slideIn 0.3s ease-out;
                max-width: 400px;
            }
            @keyframes slideIn {
                from { transform: translateX(100%); opacity: 0; }
                to { transform: translateX(0); opacity: 1; }
            }
            .notification-success { background: linear-gradient(to right, #00b894, #00cec9); }
            .notification-error { background: linear-gradient(to right, #e84343, #fd79a8); }
            .notification-warning { background: linear-gradient(to right, #fdcb6e, #e17055); }
            .notification-info { background: linear-gradient(to right, #6a11cb, #2575fc); }
            .notification i { font-size: 1.3rem; }
        `;

        document.head.appendChild(style);
        document.body.appendChild(notification);

        // 3秒后自动移除
        setTimeout(() => {
            notification.style.animation = 'slideOut 0.3s ease-in forwards';

            const slideOutStyle = document.createElement('style');
            slideOutStyle.textContent = `
                @keyframes slideOut {
                    from { transform: translateX(0); opacity: 1; }
                    to { transform: translateX(100%); opacity: 0; }
                }
            `;
            document.head.appendChild(slideOutStyle);

            setTimeout(() => {
                if (notification.parentNode) {
                    notification.remove();
                }
                if (style.parentNode) {
                    style.remove();
                }
                if (slideOutStyle.parentNode) {
                    slideOutStyle.remove();
                }
            }, 300);
        }, 3000);
    }

    // HTML转义防止XSS
    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

