/* 基础重置 */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Poppins', sans-serif;
    background: linear-gradient(135deg, #6a11cb 0%, #2575fc 100%);
    color: #333;
    min-height: 100vh;
    padding: 20px;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    width: 100%;
    max-width: 900px;
    background-color: rgba(255, 255, 255, 0.95);
    border-radius: 24px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    overflow: hidden;
    padding: 30px;
    margin: 20px;
}

/* 头部样式 */
header {
    text-align: center;
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 2px solid #f0f0f0;
}

header h1 {
    font-size: 2.8rem;
    color: #2d3436;
    margin-bottom: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 15px;
}

header h1 i {
    color: #6a11cb;
}

.subtitle {
    font-size: 1.2rem;
    color: #636e72;
    font-weight: 300;
}

/* 应用包装器 */
.app-wrapper {
    display: flex;
    flex-direction: column;
    gap: 25px;
}

/* 输入区域 */
.input-section {
    background-color: #f8f9fa;
    padding: 25px;
    border-radius: 18px;
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.05);
}

.input-group {
    display: flex;
    gap: 15px;
    margin-bottom: 20px;
}

#taskInput {
    flex: 1;
    padding: 18px 20px;
    border: 2px solid #dfe6e9;
    border-radius: 12px;
    font-size: 1.1rem;
    font-family: 'Poppins', sans-serif;
    transition: all 0.3s ease;
}

#taskInput:focus {
    outline: none;
    border-color: #6a11cb;
    box-shadow: 0 0 0 3px rgba(106, 17, 203, 0.2);
}

#addBtn {
    background: linear-gradient(to right, #6a11cb, #2575fc);
    color: white;
    border: none;
    padding: 18px 30px;
    border-radius: 12px;

