     1→// 待办事项应用
     2→class TodoApp {
     3→    constructor() {
     4→        this.tasks = JSON.parse(localStorage.getItem('todoTasks')) || [];
     5→        this.currentFilter = 'all';
     6→
     7→        this.initElements();
     8→        this.bindEvents();
     9→        this.renderTasks();
    10→        this.updateStats();
    11→    }
    12→
    13→    // 初始化DOM元素
    14→    initElements() {
    15→        this.taskInput = document.getElementById('taskInput');
    16→        this.addBtn = document.getElementById('addBtn');
    17→        this.taskList = document.getElementById('taskList');
    18→        this.filterButtons = document.querySelectorAll('.filter-btn');
    19→        this.clearCompletedBtn = document.getElementById('clearCompleted');
    20→        this.saveTasksBtn = document.getElementById('saveTasks');
    21→        this.loadTasksBtn = document.getElementById('loadTasks');
    22→        this.totalTasksEl = document.getElementById('totalTasks');
    23→        this.pendingTasksEl = document.getElementById('pendingTasks');
    24→        this.completedTasksEl = document.getElementById('completedTasks');
    25→    }
    26→
    27→    // 绑定事件
    28→    bindEvents() {
    29→        // 添加任务
    30→        this.addBtn.addEventListener('click', () => this.addTask());
    31→        this.taskInput.addEventListener('keypress', (e) => {
    32→            if (e.key === 'Enter') this.addTask();
    33→        });
    34→
    35→        // 过滤按钮
    36→        this.filterButtons.forEach(btn => {
    37→            btn.addEventListener('click', () => {
    38→                this.filterButtons.forEach(b => b.classList.remove('active'));
    39→                btn.classList.add('active');
    40→                this.currentFilter = btn.dataset.filter;
    41→                this.renderTasks();
    42→            });
    43→        });
    44→
    45→        // 清除已完成
    46→        this.clearCompletedBtn.addEventListener('click', () => this.clearCompleted());
    47→
    48→        // 保存/加载任务
    49→        this.saveTasksBtn.addEventListener('click', () => this.saveTasks());
    50→        this.loadTasksBtn.addEventListener('click', () => this.loadTasks());
    51→    }
    52→
    53→    // 添加新任务
    54→    addTask() {
    55→        const text = this.taskInput.value.trim();
    56→        if (!text) {
    57→            this.showNotification('请输入任务内容', 'error');
    58→            return;
    59→        }
    60→
    61→        const newTask = {
    62→            id: Date.now(),
    63→            text: text,
    64→            completed: false,
    65→            createdAt: new Date().toISOString(),
    66→            completedAt: null
    67→        };
    68→
    69→        this.tasks.unshift(newTask);
    70→        this.saveToLocalStorage();
    71→        this.renderTasks();
    72→        this.updateStats();
    73→        this.taskInput.value = '';
    74→
    75→        this.showNotification('任务添加成功', 'success');
    76→    }
    77→
    78→    // 切换任务完成状态
    79→    toggleTask(id) {
    80→        const task = this.tasks.find(t => t.id === id);
    81→        if (task) {
    82→            task.completed = !task.completed;
    83→            task.completedAt = task.completed ? new Date().toISOString() : null;
    84→            this.saveToLocalStorage();
    85→            this.renderTasks();
    86→            this.updateStats();
    87→
    88→            const status = task.completed ? '已完成' : '待完成';
    89→            this.showNotification(`任务标记为${status}`, 'info');
    90→        }
    91→    }
    92→
    93→    // 删除任务
    94→    deleteTask(id) {
    95→        const taskIndex = this.tasks.findIndex(t => t.id === id);
    96→        if (taskIndex > -1) {
    97→            const taskText = this.tasks[taskIndex].text;
    98→            this.tasks.splice(taskIndex, 1);
    99→            this.saveToLocalStorage();
   100→            this.renderTasks();
   101→            this.updateStats();
   102→
   103→            this.showNotification(`任务"${taskText}"已删除`, 'warning');
   104→        }
   105→    }
   106→
   107→    // 编辑任务
   108→    editTask(id, newText) {
   109→        const task = this.tasks.find(t => t.id === id);
   110→        if (task && newText.trim()) {
   111→            const oldText = task.text;
   112→            task.text = newText.trim();
   113→            this.saveToLocalStorage();
   114→            this.renderTasks();
   115→
   116→            this.showNotification(`任务"${oldText}"已更新`, 'info');
   117→        }
   118→    }
   119→
   120→    // 清除已完成任务
   121→    clearCompleted() {
   122→        const completedCount = this.tasks.filter(t => t.completed).length;
   123→        if (completedCount === 0) {
   124→            this.showNotification('没有已完成的任务', 'info');
   125→            return;
   126→        }
   127→
   128→        if (confirm(`确定要删除 ${completedCount} 个已完成的任务吗？`)) {
   129→            this.tasks = this.tasks.filter(t => !t.completed);
   130→            this.saveToLocalStorage();
   131→            this.renderTasks();
   132→            this.updateStats();
   133→
   134→            this.showNotification(`已删除 ${completedCount} 个已完成任务`, 'success');
   135→        }
   136→    }
   137→
   138→    // 保存任务到本地存储
   139→    saveToLocalStorage() {
   140→        localStorage.setItem('todoTasks', JSON.stringify(this.tasks));
   141→    }
   142→
   143→    // 保存任务到文件
   144→    saveTasks() {
   145→        const dataStr = JSON.stringify(this.tasks, null, 2);
   146→        const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
   147→        const exportFileDefaultName = '待办事项_备份_' + new Date().toISOString().split('T')[0] + '.json';
   148→
   149→        const linkElement = document.createElement('a');
   150→        linkElement.setAttribute('href', dataUri);
   151→        linkElement.setAttribute('download', exportFileDefaultName);
   152→        linkElement.click();
   153→
   154→        this.showNotification('任务已保存到文件', 'success');
   155→    }
   156→
   157→    // 从文件加载任务
   158→    loadTasks() {
   159→        const input = document.createElement('input');
   160→        input.type = 'file';
   161→        input.accept = '.json';
   162→
   163→        input.onchange = (e) => {
   164→            const file = e.target.files[0];
   165→            if (!file) return;
   166→
   167→            const reader = new FileReader();
   168→            reader.onload = (event) => {
   169→                try {
   170→                    const loadedTasks = JSON.parse(event.target.result);
   171→                    if (Array.isArray(loadedTasks)) {
   172→                        // 合并任务，避免重复ID
   173→                        const existingIds = new Set(this.tasks.map(t => t.id));
   174→                        const newTasks = loadedTasks.filter(t => !existingIds.has(t.id));
   175→
   176→                        if (newTasks.length > 0) {
   177→                            this.tasks = [...this.tasks, ...newTasks];
   178→                            this.saveToLocalStorage();
   179→                            this.renderTasks();
   180→                            this.updateStats();
   181→                            this.showNotification(`成功加载 ${newTasks.length} 个任务`, 'success');
   182→                        } else {
   183→                            this.showNotification('没有新的任务可加载', 'info');
   184→                        }
   185→                    } else {
   186→                        throw new Error('文件格式不正确');
   187→                    }
   188→                } catch (error) {
   189→                    this.showNotification('文件读取失败，请检查文件格式', 'error');
   190→                }
   191→            };
   192→            reader.readAsText(file);
   193→        };
   194→
   195→        input.click();
   196→    }
   197→
   198→    // 渲染任务列表
   199→    renderTasks() {
   200→        // 根据当前过滤器筛选任务
   201→        let filteredTasks;
   202→        switch (this.currentFilter) {
   203→            case 'pending':
   204→                filteredTasks = this.tasks.filter(t => !t.completed);
   205→                break;
   206→            case 'completed':
   207→                filteredTasks = this.tasks.filter(t => t.completed);
   208→                break;
   209→            default:
   210→                filteredTasks = this.tasks;
   211→        }
   212→
   213→        // 清空任务列表
   214→        this.taskList.innerHTML = '';
   215→
   216→        // 如果没有任务，显示空状态
   217→        if (filteredTasks.length === 0) {
   218→            const emptyState = document.createElement('div');
   219→            emptyState.className = 'empty-state';
   220→            emptyState.innerHTML = `
   221→                <i class="fas fa-clipboard"></i>
   222→                <p>${this.currentFilter === 'all' ? '暂无任务，添加您的第一个待办事项吧！' :
   223→                    this.currentFilter === 'pending' ? '没有待完成的任务' :
   224→                    '没有已完成的任务'}</p>
   225→            `;
   226→            this.taskList.appendChild(emptyState);
   227→            return;
   228→        }
   229→
   230→        // 渲染每个任务
   231→        filteredTasks.forEach(task => {
