   241→        taskItem.dataset.id = task.id;
   242→
   243→        // 格式化时间
   244→        const createdTime = new Date(task.createdAt).toLocaleString('zh-CN');
   245→        const completedTime = task.completedAt ?
   246→            new Date(task.completedAt).toLocaleString('zh-CN') : '';
   247→
   248→        taskItem.innerHTML = `
   249→            <input type="checkbox" class="task-checkbox" ${task.completed ? 'checked' : ''}>
   250→            <div class="task-content">
   251→                <div>${this.escapeHtml(task.text)}</div>
   252→                <div class="task-time">
   253→                    <i class="far fa-calendar-plus"></i> ${createdTime}
   254→                    ${completedTime ? `<br><i class="far fa-calendar-check"></i> ${completedTime}` : ''}
   255→                </div>
   256→            </div>
   257→            <div class="task-actions">
   258→                <button class="task-btn edit-btn"><i class="fas fa-edit"></i></button>
   259→                <button class="task-btn delete-btn"><i class="fas fa-trash"></i></button>
   260→            </div>
   261→        `;
   262→
   263→        // 绑定事件
   264→        const checkbox = taskItem.querySelector('.task-checkbox');
   265→        const editBtn = taskItem.querySelector('.edit-btn');
   266→        const deleteBtn = taskItem.querySelector('.delete-btn');
   267→
   268→        checkbox.addEventListener('change', () => this.toggleTask(task.id));
   269→        deleteBtn.addEventListener('click', () => this.deleteTask(task.id));
   270→        editBtn.addEventListener('click', () => this.enterEditMode(taskItem, task));
