   307→        // 取消编辑
   308→        cancelBtn.addEventListener('click', () => {
   309→            taskContent.innerHTML = originalHTML;
   310→            taskActions.innerHTML = originalActions;
   311→            this.bindTaskEvents(taskItem, task.id);
   312→        });
   313→
   314→        // 按Enter保存，按Escape取消
   315→        editInput.addEventListener('keypress', (e) => {
   316→            if (e.key === 'Enter') {
   317→                this.editTask(task.id, editInput.value);
   318→            }
   319→        });
   320→
   321→        editInput.addEventListener('keydown', (e) => {
   322→            if (e.key === 'Escape') {
   323→                taskContent.innerHTML = originalHTML;
   324→                taskActions.innerHTML = originalActions;
   325→                this.bindTaskEvents(taskItem, task.id);
   326→            }
   327→        });
   328→    }
   329→
   330→    // 绑定任务事件（编辑模式退出后）
   331→    bindTaskEvents(taskItem, taskId) {
   332→        const checkbox = taskItem.querySelector('.task-checkbox');
   333→        const editBtn = taskItem.querySelector('.edit-btn');
   334→        const deleteBtn = taskItem.querySelector('.delete-btn');
   335→
   336→        checkbox.addEventListener('change', () => this.toggleTask(taskId));
   337→        deleteBtn.addEventListener('click', () => this.deleteTask(taskId));
   338→        editBtn.addEventListener('click', () => {
   339→            const task = this.tasks.find(t => t.id === taskId);
   340→            if (task) this.enterEditMode(taskItem, task);
   341→        });
   342→    }
   343→
   344→    // 更新统计信息
   345→    updateStats() {
   346→        const total = this.tasks.length;
   347→        const completed = this.tasks.filter(t => t.completed).length;
   348→        const pending = total - completed;
   349→
   350→        this.totalTasksEl.textContent = total;
   351→        this.pendingTasksEl.textContent = pending;
   352→        this.completedTasksEl.textContent = completed;
   353→    }
   354→
   355→    // 显示通知
   356→    showNotification(message, type = 'info') {
   357→        // 移除现有的通知
   358→        const existingNotification = document.querySelector('.notification');
   359→        if (existingNotification) {
   360→            existingNotification.remove();
   361→        }
   362→
   363→        // 创建新通知
   364→        const notification = document.createElement('div');
   365→        notification.className = `notification notification-${type}`;
   366→        notification.innerHTML = `
   367→            <i class="fas fa-${type === 'success' ? 'check-circle' : type === 'error' ? 'exclamation-circle' : type === 'warning' ? 'exclamation-triangle' : 'info-circle'}"></i>
   368→            <span>${message}</span>
   369→        `;
   370→
   371→        // 添加样式
   372→        const style = document.createElement('style');
   373→        style.textContent = `
   374→            .notification {
   375→                position: fixed;
   376→                top: 20px;
   377→                right: 20px;
   378→                padding: 15px 25px;
   379→                border-radius: 12px;
   380→                color: white;
   381→                font-weight: 500;
   382→                display: flex;
   383→                align-items: center;
   384→                gap: 12px;
   385→                box-shadow: 0 10px 30px rgba(0,0,0,0.2);
   386→                z-index: 1000;
   387→                animation: slideIn 0.3s ease-out;
   388→                max-width: 400px;
   389→            }
   390→            @keyframes slideIn {
   391→                from { transform: translateX(100%); opacity: 0; }
   392→                to { transform: translateX(0); opacity: 1; }
   393→            }
   394→            .notification-success { background: linear-gradient(to right, #00b894, #00cec9); }
   395→            .notification-error { background: linear-gradient(to right, #e84343, #fd79a8); }
   396→            .notification-warning { background: linear-gradient(to right, #fdcb6e, #e17055); }
   397→            .notification-info { background: linear-gradient(to right, #6a11cb, #2575fc); }
   398→            .notification i { font-size: 1.3rem; }
   399→        `;
   400→
   401→        document.head.appendChild(style);
   402→        document.body.appendChild(notification);
   403→
   404→        // 3秒后自动移除
   405→        setTimeout(() => {
   406→            notification.style.animation = 'slideOut 0.3s ease-in forwards';
   407→
   408→            const slideOutStyle = document.createElement('style');
   409→            slideOutStyle.textContent = `
   410→                @keyframes slideOut {
   411→                    from { transform: translateX(0); opacity: 1; }
   412→                    to { transform: translateX(100%); opacity: 0; }
   413→                }
   414→            `;
   415→            document.head.appendChild(slideOutStyle);
   416→
   417→            setTimeout(() => {
   418→                if (notification.parentNode) {
   419→                    notification.remove();
   420→                }
   421→                if (style.parentNode) {
   422→                    style.remove();
   423→                }
   424→                if (slideOutStyle.parentNode) {
   425→                    slideOutStyle.remove();
   426→                }
   427→            }, 300);
   428→        }, 3000);
   429→    }
