/**
 * 日期工具函数
 */

/**
 * 获取当前时间的ISO字符串
 */
export function getCurrentISOTime(): string {
  return new Date().toISOString();
}

/**
 * 格式化日期为本地字符串（中文）
 */
export function formatDateToLocal(isoDate: string): string {
  return new Date(isoDate).toLocaleString('zh-CN');
}

/**
 * 格式化日期为相对时间（如"刚刚"、"5分钟前"）
 */
export function formatRelativeTime(isoDate: string): string {
  const date = new Date(isoDate);
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / (1000 * 60));
  const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
  const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (diffMins < 1) {
    return '刚刚';
  } else if (diffMins < 60) {
    return `${diffMins}分钟前`;
  } else if (diffHours < 24) {
    return `${diffHours}小时前`;
  } else if (diffDays < 7) {
    return `${diffDays}天前`;
  } else {
    return formatDateToLocal(isoDate);
  }
}

/**
 * 获取友好的日期时间显示
 */
export function getFriendlyDateTime(isoDate: string): string {
  const date = new Date(isoDate);
  const now = new Date();
  const isToday = date.toDateString() === now.toDateString();

  if (isToday) {
    return `今天 ${date.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' })}`;
  }

  const isYesterday = new Date(now.getTime() - 86400000).toDateString() === date.toDateString();
  if (isYesterday) {
    return `昨天 ${date.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' })}`;
  }

  return formatDateToLocal(isoDate);
}

