saveTasks() {
    const dataStr = JSON.stringify(this.tasks, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const exportFileDefaultName = '待办事项_备份_' + new Date().toISOString().split('T')[0] + '.json';

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();

    this.showNotification('任务已保存到文件', 'success');
}

// 从文件加载任务
loadTasks() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';

    input.onchange = (e) => {
        const file = e.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            try {
                const loadedTasks = JSON.parse(event.target.result);
                if (Array.isArray(loadedTasks)) {
                    // 合并任务，避免重复ID
                    const existingIds = new Set(this.tasks.map(t => t.id));
                    const newTasks = loadedTasks.filter(t => !existingIds.has(t.id));

                    if (newTasks.length > 0) {
                        this.tasks = [...this.tasks, ...newTasks];
                        this.saveToLocalStorage();
                        this.renderTasks();
                        this.updateStats();
                        this.showNotification(`成功加载 ${newTasks.length} 个任务`, 'success');
                    } else {
                        this.showNotification('没有新的任务可加载', 'info');
                    }
                } else {
                    throw new Error('文件格式不正确');
                }
            } catch (error) {
                this.showNotification('文件读取失败，请检查文件格式', 'error');
            }
        };
        reader.readAsText(file);
    };

    input.click();
}

// 渲染任务列表
renderTasks() {
    // 根据当前过滤器筛选任务
    let filteredTasks;
    switch (this.currentFilter) {
        case 'pending':
            filteredTasks = this.tasks.filter(t => !t.completed);
            break;
        case 'completed':
            filteredTasks = this.tasks.filter(t => t.completed);
            break;
        default:
            filteredTasks = this.tasks;
    }

    // 清空任务列表
    this.taskList.innerHTML = '';

    // 如果没有任务，显示空状态
    if (filteredTasks.length === 0) {
        const emptyState = document.createElement('div');
        emptyState.className = 'empty-state';
        emptyState.innerHTML = `
            <i class="fas fa-clipboard"></i>
            <p>${this.currentFilter === 'all' ? '暂无任务，添加您的第一个待办事项吧！' :
                this.currentFilter === 'pending' ? '没有待完成的任务' :

