input.content:
/**
 * 验证和工具函数
 */

/**
 * HTML转义防止XSS攻击
 * 原实现：使用textContent设置然后获取innerHTML
 */
export function escapeHtml(text: string): string {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

/**
 * 验证任务文本是否有效
 */
export function validateTaskText(text: string): { valid: boolean; message?: string } {
  const trimmed = text.trim();

  if (trimmed.length === 0) {
    return { valid: false, message: '任务内容不能为空' };
  }

  if (trimmed.length > 500) {
    return { valid: false, message: '任务内容不能超过500个字符' };
  }

  return { valid: true };
}

/**
 * 验证任务对象是否有效
 */
export function validateTask(task: any): { valid: boolean; message?: string } {
  if (!task || typeof task !== 'object') {
    return { valid: false, message: '任务数据无效' };
  }

  if (typeof task.id !== 'number' || task.id <= 0) {
    return { valid: false, message: '任务ID无效' };
  }

  const textValidation = validateTaskText(task.text);
  if (!textValidation.valid) {
    return textValidation;
  }

  if (typeof task.completed !== 'boolean') {
    return { valid: false, message: '完成状态无效' };
  }

  if (typeof task.createdAt !== 'string' || isNaN(Date.parse(task.createdAt))) {
    return { valid: false, message: '创建时间格式无效' };
  }

  if (task.completedAt !== null && (typeof task.completedAt !== 'string' || isNaN(Date.parse(task.completedAt)))) {
    return { valid: false, message: '完成时间格式无效' };
  }

  return { valid: true };
}

/**
 * 生成新的任务ID（时间戳）
 */
export function generateTaskId(): number {
  return Date.now();
}

/**
 * 深度克隆对象（简单实现）
