import { defineStore } from 'pinia';
import { ref, computed, watch } from 'vue';
import type { Task, FilterType, Stats } from '@/types';
import { generateTaskId, validateTaskText, validateTask } from '@/utils/validation';
import { saveTasksToLocalStorage, loadTasksFromLocalStorage } from '@/utils/localStorage';
import { exportTasksToFile, importTasksFromFile, filterDuplicateTasks } from '@/utils/fileUtils';
import { getCurrentISOTime } from '@/utils/dateUtils';

export const useTaskStore = defineStore('tasks', () => {
  // 状态
  const tasks = ref<Task[]>([]);
  const currentFilter = ref<FilterType>('all');
  const isLoading = ref(false);
  const error = ref<string | null>(null);

  // 初始化：从本地存储加载任务
  const initialize = () => {
    try {
      isLoading.value = true;
      const loadedTasks = loadTasksFromLocalStorage();
      tasks.value = loadedTasks;
      error.value = null;

      // 如果没有任务，添加示例任务
      if (tasks.value.length === 0) {
        addSampleTasks();
      }
    } catch (err) {
      error.value = `加载任务失败: ${(err as Error).message}`;
      console.error('初始化失败:', err);
    } finally {
      isLoading.value = false;
    }
  };

  // 添加示例任务
  const addSampleTasks = () => {
    const sampleTasks: Task[] = [
      {
        id: generateTaskId(),
        text: '欢迎使用待办事项软件',
        completed: true,
        createdAt: new Date(Date.now() - 86400000).toISOString(),
        completedAt: new Date(Date.now() - 43200000).toISOString(),
      },
      {
        id: generateTaskId(),
        text: '点击复选框标记任务完成',
        completed: false,
        createdAt: new Date(Date.now() - 72000000).toISOString(),
        completedAt: null,
      },
      {
        id: generateTaskId(),
        text: '使用编辑按钮修改任务',
        completed: false,
        createdAt: new Date(Date.now() - 36000000).toISOString(),
        completedAt: null,
      },
      {
        id: generateTaskId(),
        text: '尝试过滤功能查看不同状态的任务',
        completed: false,
        createdAt: getCurrentISOTime(),
        completedAt: null,
      },
    ];

    tasks.value = sampleTasks;
    saveToLocalStorage();
  };

  // 计算属性（Getters）
  const filteredTasks = computed(() => {
    switch (currentFilter.value) {
      case 'pending':
        return tasks.value.filter(task => !task.completed);
      case 'completed':
        return tasks.value.filter(task => task.completed);
      default:
        return tasks.value;
    }
  });

  const stats = computed<Stats>(() => {
    const total = tasks.value.length;
    const completed = tasks.value.filter(task => task.completed).length;
    const pending = total - completed;

    return {
      total,
      pending,
      completed,
    };
  });

  const hasTasks = computed(() => tasks.value.length > 0);
  const hasCompletedTasks = computed(() => tasks.value.some(task => task.completed));

  // Actions（操作）
  const addTask = (text: string): { success: boolean; message?: string } => {
    const validation = validateTaskText(text);
    if (!validation.valid) {
      return { success: false, message: validation.message };
    }

    try {
      const newTask: Task = {
        id: generateTaskId(),
        text: text.trim(),
        completed: false,
        createdAt: getCurrentISOTime(),
        completedAt: null,
      };

      tasks.value.unshift(newTask); // 新任务添加到开头
      saveToLocalStorage();
      return { success: true };
    } catch (err) {
      error.value = `添加任务失败: ${(err as Error).message}`;
      return { success: false, message: '添加任务失败' };
    }
  };

  const toggleTask = (id: number): boolean => {
    const taskIndex = tasks.value.findIndex(task => task.id === id);
    if (taskIndex === -1) {
      return false;
    }

    const task = tasks.value[taskIndex];
    task.completed = !task.completed;
    task.completedAt = task.completed ? getCurrentISOTime() : null;

    // 更新数组以触发响应式更新
    tasks.value[taskIndex] = { ...task };
    saveToLocalStorage();
    return true;
  };

  const deleteTask = (id: number): boolean => {
    const taskIndex = tasks.value.findIndex(task => task.id === id);
    if (taskIndex === -1) {
      return false;
    }

    tasks.value.splice(taskIndex, 1);
    saveToLocalStorage();
    return true;
  };

  const editTask = (id: number, newText: string): { success: boolean; message?: string } => {
    const validation = validateTaskText(newText);
    if (!validation.valid) {
      return { success: false, message: validation.message };
    }

    const taskIndex = tasks.value.findIndex(task => task.id === id);
    if (taskIndex === -1) {
      return { success: false, message: '任务不存在' };
    }

    const task = tasks.value[taskIndex];
    task.text = newText.trim();

    // 更新数组以触发响应式更新
    tasks.value[taskIndex] = { ...task };
    saveToLocalStorage();
    return { success: true };
  };

  const clearCompleted = (): number => {
    const completedCount = tasks.value.filter(task => task.completed).length;
    if (completedCount === 0) {
      return 0;
    }

    tasks.value = tasks.value.filter(task => !task.completed);
    saveToLocalStorage();
    return completedCount;
  };

  const setFilter = (filter: FilterType) => {
    currentFilter.value = filter;
  };

  const saveToLocalStorage = () => {
    try {
      saveTasksToLocalStorage(tasks.value);
    } catch (err) {
      error.value = `保存到本地存储失败: ${(err as Error).message}`;
      console.error('保存失败:', err);
    }
  };

  const exportTasks = () => {
    try {
      exportTasksToFile(tasks.value);
      return { success: true };
    } catch (err) {
      error.value = `导出任务失败: ${(err as Error).message}`;
      return { success: false, message: '导出任务失败' };
    }
  };

  const importTasks = async (): Promise<{ success: boolean; message?: string; count?: number }> => {
    try {
      const importedTasks = await importTasksFromFile();
      const newTasks = filterDuplicateTasks(tasks.value, importedTasks);

      if (newTasks.length === 0) {
        return { success: true, message: '没有新的任务可导入', count: 0 };
      }

      tasks.value = [...tasks.value, ...newTasks];
      saveToLocalStorage();
      return { success: true, message: `成功导入 ${newTasks.length} 个任务`, count: newTasks.length };
    } catch (err) {
      error.value = `导入任务失败: ${(err as Error).message}`;
      return { success: false, message: '导入任务失败' };
    }
  };

  // 自动保存：监听tasks变化并保存到本地存储
  watch(
    () => tasks.value,
    () => {
      saveToLocalStorage();
    },
    { deep: true }
  );

  return {
    // 状态
    tasks,
    currentFilter,
    isLoading,
    error,

    // 计算属性
    filteredTasks,
    stats,
    hasTasks,
    hasCompletedTasks,

    // Actions
    initialize,
    addTask,
    toggleTask,
    deleteTask,
    editTask,
    clearCompleted,
    setFilter,
    exportTasks,
    importTasks,
    saveToLocalStorage,
  };
});

