import { ref, onUnmounted } from 'vue';
import type { Notification } from '@/types';

export type NotificationType = 'success' | 'error' | 'warning' | 'info';

export interface NotificationOptions {
  type?: NotificationType;
  duration?: number; // 毫秒，0表示不自动关闭
  closable?: boolean;
}

const defaultOptions: Required<NotificationOptions> = {
  type: 'info',
  duration: 3000,
  closable: true,
};

export function useNotifications() {
  const notifications = ref<Notification[]>([]);
  let nextId = 1;

  const show = (message: string, options: NotificationOptions = {}): number => {
    const mergedOptions = { ...defaultOptions, ...options };
    const id = nextId++;

    const notification: Notification = {
      id,
      message,
      type: mergedOptions.type,
      visible: true,
    };

    notifications.value.push(notification);

    // 自动关闭
    if (mergedOptions.duration > 0) {
      setTimeout(() => {
        hide(id);
      }, mergedOptions.duration);
    }

    return id;
  };

  const hide = (id: number) => {
    const index = notifications.value.findIndex(n => n.id === id);
    if (index !== -1) {
      notifications.value.splice(index, 1);
    }
  };

  const hideAll = () => {
    notifications.value = [];
  };

  const success = (message: string, options?: Omit<NotificationOptions, 'type'>) => {
    return show(message, { ...options, type: 'success' });
  };

  const error = (message: string, options?: Omit<NotificationOptions, 'type'>) => {
    return show(message, { ...options, type: 'error' });
  };

  const warning = (message: string, options?: Omit<NotificationOptions, 'type'>) => {
    return show(message, { ...options, type: 'warning' });
  };

  const info = (message: string, options?: Omit<NotificationOptions, 'type'>) => {
    return show(message, { ...options, type: 'info' });
  };

  // 组件卸载时清理所有通知
  onUnmounted(() => {
    hideAll();
  });

  return {
    notifications,
    show,
    hide,
    hideAll,
    success,
    error,
    warning,
    info,
  };
}

