/* CSS变量定义 */
:root {
  /* 颜色系统 */
  --color-primary: #6a11cb;
  --color-primary-light: #7a2bdb;
  --color-primary-dark: #5a0ab3;
  --color-secondary: #2575fc;
  --color-success: #00b894;
  --color-success-light: #00cec9;
  --color-error: #e84343;
  --color-error-light: #fd79a8;
  --color-warning: #fdcb6e;
  --color-warning-dark: #e17055;
  --color-info: #6a11cb;
  --color-info-light: #2575fc;

  /* 渐变 */
  --gradient-primary: linear-gradient(135deg, #6a11cb 0%, #2575fc 100%);
  --gradient-success: linear-gradient(to right, #00b894, #00cec9);
  --gradient-error: linear-gradient(to right, #e84343, #fd79a8);
  --gradient-warning: linear-gradient(to right, #fdcb6e, #e17055);
  --gradient-info: linear-gradient(to right, #6a11cb, #2575fc);
  --gradient-dark: linear-gradient(to right, #636e72, #2d3436);

  /* 中性色 */
  --color-white: #ffffff;
  --color-gray-50: #f8f9fa;
  --color-gray-100: #f1f3f4;
  --color-gray-200: #e9ecef;
  --color-gray-300: #dfe6e9;
  --color-gray-400: #b2bec3;
  --color-gray-500: #636e72;
  --color-gray-600: #2d3436;
  --color-gray-700: #1a1e1f;
  --color-black: #000000;

  /* 阴影 */
  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.05);
  --shadow-md: 0 5px 15px rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 8px 20px rgba(0, 0, 0, 0.05);
  --shadow-xl: 0 10px 30px rgba(0, 0, 0, 0.1);
  --shadow-xxl: 0 20px 60px rgba(0, 0, 0, 0.3);

  /* 圆角 */
  --radius-xs: 4px;
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 18px;
  --radius-xl: 24px;
  --radius-round: 50%;

  /* 间距 */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 16px;
  --space-lg: 24px;
  --space-xl: 32px;
  --space-xxl: 48px;

  /* 字体 */
  --font-family: 'Poppins', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
  --font-size-xs: 0.75rem;   /* 12px */
  --font-size-sm: 0.875rem;  /* 14px */
  --font-size-md: 1rem;      /* 16px */
  --font-size-lg: 1.125rem;  /* 18px */
  --font-size-xl: 1.25rem;   /* 20px */
  --font-size-2xl: 1.5rem;   /* 24px */
  --font-size-3xl: 1.875rem; /* 30px */
  --font-size-4xl: 2.25rem;  /* 36px */
  --font-size-5xl: 3rem;     /* 48px */

  /* 字体权重 */
  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* 过渡 */
  --transition-fast: 150ms ease;
  --transition-normal: 300ms ease;
  --transition-slow: 500ms ease;

  /* 层级 */
  --z-index-dropdown: 1000;
  --z-index-sticky: 1020;
  --z-index-fixed: 1030;
  --z-index-modal-backdrop: 1040;
  --z-index-modal: 1050;
  --z-index-popover: 1060;
  --z-index-tooltip: 1070;
  --z-index-notification: 1080;
}

