  const task = taskStore.tasks.find(t => t.id === id);
  const result = taskStore.editTask(id, newText);
  if (result.success && task) {
    notifications.info(`任务"${task.text}"已更新`);
  } else if (result.message) {
    notifications.error(result.message);
  }
};

