/**
 * 本地存储工具函数
 */
import type { Task } from '@/types';

const STORAGE_KEY = 'todoTasks';

/**
 * 保存任务到本地存储
 */
export function saveTasksToLocalStorage(tasks: Task[]): void {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
  } catch (error) {
    console.error('保存到本地存储失败:', error);
    throw new Error('保存数据失败，请检查存储空间');
  }
}

/**
 * 从本地存储加载任务
 */
export function loadTasksFromLocalStorage(): Task[] {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) {
      return [];
    }

    const tasks = JSON.parse(stored);
    if (!Array.isArray(tasks)) {
      console.warn('本地存储中的数据格式不正确，重置为空数组');
      return [];
    }

    // 验证任务数据
    const validTasks: Task[] = [];
    for (const task of tasks) {
      if (
        task &&
        typeof task.id === 'number' &&
        typeof task.text === 'string' &&
        typeof task.completed === 'boolean' &&
        typeof task.createdAt === 'string'
      ) {
        validTasks.push({
          id: task.id,
          text: task.text,
          completed: task.completed,
          createdAt: task.createdAt,
          completedAt: task.completedAt === null || typeof task.completedAt === 'string'
            ? task.completedAt
            : null,
        });
      }
    }

    return validTasks;
  } catch (error) {
    console.error('从本地存储加载失败:', error);
    return [];
  }
}

/**
 * 清除本地存储中的任务数据
 */
export function clearTasksFromLocalStorage(): void {
  try {
    localStorage.removeItem(STORAGE_KEY);
  } catch (error) {
    console.error('清除本地存储失败:', error);
  }
}

/**
 * 检查本地存储是否可用
 */
export function isLocalStorageAvailable(): boolean {
  try {
    const testKey = '__test__';
    localStorage.setItem(testKey, testKey);
    localStorage.removeItem(testKey);
    return true;
  } catch (error) {
    console.warn('本地存储不可用:', error);
    return false;
  }
}

