/**
 * 文件操作工具函数
 */
import type { Task } from '@/types';

/**
 * 导出任务为JSON文件
 */
export function exportTasksToFile(tasks: Task[]): void {
  const dataStr = JSON.stringify(tasks, null, 2);
  const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
  const exportFileDefaultName = `待办事项_备份_${new Date().toISOString().split('T')[0]}.json`;

  const linkElement = document.createElement('a');
  linkElement.setAttribute('href', dataUri);
  linkElement.setAttribute('download', exportFileDefaultName);
  linkElement.click();
}

/**
 * 从文件导入任务
 * @returns 返回一个Promise，解析为导入的任务数组
 */
export function importTasksFromFile(): Promise<Task[]> {
  return new Promise((resolve, reject) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';

    input.onchange = (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) {
        reject(new Error('未选择文件'));
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const result = event.target?.result;
          if (typeof result !== 'string') {
            reject(new Error('文件读取失败'));
            return;
          }

          const loadedTasks = JSON.parse(result);
          if (!Array.isArray(loadedTasks)) {
            reject(new Error('文件格式不正确，应为任务数组'));
            return;
          }

          // 验证任务结构
          const validTasks = loadedTasks.filter((task: any) => {
            return (
              typeof task.id === 'number' &&
              typeof task.text === 'string' &&
              typeof task.completed === 'boolean' &&
              typeof task.createdAt === 'string' &&
              (task.completedAt === null || typeof task.completedAt === 'string')
            );
          });

          if (validTasks.length === 0) {
            reject(new Error('文件中没有有效的任务数据'));
            return;
          }

          resolve(validTasks as Task[]);
        } catch (error) {
          reject(new Error('文件解析失败：' + (error as Error).message));
        }
      };

      reader.onerror = () => {
        reject(new Error('文件读取失败'));
      };

      reader.readAsText(file);
    };

    input.oncancel = () => {
      reject(new Error('用户取消了文件选择'));
    };

    input.click();
  });
}

/**
 * 过滤重复任务（基于ID）
 */
export function filterDuplicateTasks(existingTasks: Task[], newTasks: Task[]): Task[] {
  const existingIds = new Set(existingTasks.map(t => t.id));
  return newTasks.filter(task => !existingIds.has(task.id));
}
